import { useEffect, useMemo, useRef } from 'react';
import type { AccountSearchMode, CreateAccountSearchConfigOptions } from '@linm-soft-org/linm-web-common-components';
import { clearAccountSearchCache } from './accountSearchConfig';

/** Normalize ISO / datetime input to YYYY-MM-DD for account search API. */
export function normalizeAccountAsOfDate(iso?: string): string | undefined {
  const d = iso?.trim();
  if (!d) return undefined;
  return d.slice(0, 10);
}

/** Memoized `asOfDate` for AccountSearchInput + clear catalog cache when date changes. */
export function useAccountSearchAsOfDate(
  asOfDate?: string,
  mode?: AccountSearchMode,
): CreateAccountSearchConfigOptions {
  const normalized = normalizeAccountAsOfDate(asOfDate);
  const prevRef = useRef<string | undefined>();

  useEffect(() => {
    if (prevRef.current !== normalized) {
      prevRef.current = normalized;
      clearAccountSearchCache();
    }
  }, [normalized]);

  return useMemo(
    () => ({
      ...(mode ? { mode } : {}),
      ...(normalized ? { asOfDate: normalized } : {}),
    }),
    [normalized, mode],
  );
}
