import type { CashVoucherKind } from '../components/kt/CashVoucherList';
import type { CashVoucherShellId } from '../features/kt/cash-voucher/shared/config/cashVoucherShellProfiles';

/** Nhãn loại đối tượng master — parity `reportPageLabels.congNo`. */
export const CUSTOMER_TYPE_LABELS: Record<string, string> = {
  Customer: 'Khách hàng',
  Supplier: 'Nhà cung cấp',
  Both: 'KH & NCC',
};

export type CustomerTypeCode = keyof typeof CUSTOMER_TYPE_LABELS;

/** Badge variant — KH (info) · NCC (secondary + CSS tím) · Both (success). Cấm warning (trùng lỗi). */
export type CustomerTypeBadgeVariant = 'info' | 'success' | 'secondary';

const CUSTOMER_TYPE_BADGE_VARIANT: Record<CustomerTypeCode, CustomerTypeBadgeVariant> = {
  Customer: 'info',
  Supplier: 'secondary',
  Both: 'success',
};

export function getCustomerTypeBadgeVariant(
  customerType?: string | null,
): CustomerTypeBadgeVariant {
  const key = customerType?.trim() as CustomerTypeCode | undefined;
  if (!key) return 'secondary';
  return CUSTOMER_TYPE_BADGE_VARIANT[key] ?? 'secondary';
}

/** Placeholder ô tìm đối tượng — đồng bộ mọi CT tiền (PT/PC/BC/BN/UNC). */
export const PARTNER_FIELD_PLACEHOLDER = 'Chọn đối tượng chi tiết';

/**
 * «Bên tương ứng» theo loại chứng từ — SSOT map Đối tượng (…).
 * Đối tượng có thể là KH / NCC / Both; loại hiển thị riêng khi user chọn.
 */
export const PARTNER_SIDE_LABELS: Record<CashVoucherShellId, string> = {
  'phieu-thu': 'Bên nộp',
  'phieu-chi': 'Bên nhận',
  'giay-bao-co': 'Bên chuyển khoản',
  'giay-bao-no': 'Bên nhận',
  'uy-nhiem-chi': 'Bên thụ hưởng',
};

export function getCustomerTypeLabel(customerType?: string | null): string | undefined {
  const key = customerType?.trim();
  if (!key) return undefined;
  return CUSTOMER_TYPE_LABELS[key] ?? key;
}

export function resolvePartnerSideLabel(shellId: CashVoucherShellId, kind: CashVoucherKind): string {
  return PARTNER_SIDE_LABELS[shellId]
    ?? (kind === 'receipt' ? PARTNER_SIDE_LABELS['phieu-thu'] : PARTNER_SIDE_LABELS['phieu-chi']);
}

/** Nhãn field cố định (chưa chọn loại ĐT) — dùng validation banner. */
export function formatPartnerFieldLabel(sideLabel: string): string {
  return `Đối tượng (${sideLabel})`;
}

/** Nhãn field khi đã chọn ĐT — kèm loại (KH/NCC) cho review sau. */
export function formatPartnerFieldLabelWithType(
  sideLabel: string,
  customerType?: string | null,
): string {
  const typeLabel = getCustomerTypeLabel(customerType);
  const base = formatPartnerFieldLabel(sideLabel);
  return typeLabel ? `${base} · ${typeLabel}` : base;
}
